#include <stdio.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; // unused
        char s[101];
        scanf("%d", &N);
        scanf("%100s", s);
        int len = 0;
        while (s[len] != '\0') ++len;
        printf("%d\n", len);
    }
    return 0;
}

